// RIGHT: defensive load with version, defaults, and migration
const CURRENT_VERSION = 2;
const DEFAULT_SAVE = { version: CURRENT_VERSION, score: 0, level: 1, unlocks: [] };

function loadSave() {
  try {
    const raw = localStorage.getItem('save');
    if (!raw) return { ...DEFAULT_SAVE };
    const parsed = JSON.parse(raw);
    return migrate(parsed);
  } catch (e) {
    console.warn('Save corrupt, resetting:', e);
    return { ...DEFAULT_SAVE };
  }
}

function migrate(save) {
  if (!save.version) save = { ...save, version: 1, unlocks: [] }; // v0 -> v1
  if (save.version === 1) save = { ...save, version: 2 };          // v1 -> v2 (no field changes here)
  return { ...DEFAULT_SAVE, ...save };  // fill any missing fields
}

function saveSave(save) {
  try { localStorage.setItem('save', JSON.stringify(save)); }
  catch (e) { console.warn('Save failed (quota or disabled):', e); }
}

