    const r = canvas.getBoundingClientRect();
    const gx = (cx - r.left) * (this.cameras.main.width / r.width);
    const gy = (cy - r.top) * (this.cameras.main.height / r.height);
    for (const b of this._buttons) {
      if (Math.abs(gx - b.x) <= b.w/2 && Math.abs(gy - b.y) <= b.h/2) { b.onClick(); return; }
    }
  };
  this._domHandler = (e) => onDown(e.clientX, e.clientY);
  canvas.addEventListener('mousedown', this._domHandler);
  this.events.once('shutdown', () => canvas.removeEventListener('mousedown', this._domHandler));
  // Keyboard fallback
  this.input.keyboard.on('keydown-ENTER', () => this.scene.start('Game'));
}

